// Regenerate src/engine/object-templates.ts from the frontend's object library
// manifest (apps/web/public/assets/objects/library.json — built by the
// apps/web/scripts/objects/*.py pipeline). The world server needs its OWN copy
// of the template vocabulary so place_object can validate names and agents can
// search it without a cross-app runtime dependency; this script is the sync
// mechanism (same split-source convention as zone-bounds.ts / LOCATION_ANCHORS).
//
//   node scripts/gen-object-templates.mjs
//
// Commit the regenerated file whenever the library changes.

import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const libraryPath = join(here, "../../web/public/assets/objects/library.json");
const outPath = join(here, "../src/engine/object-templates.ts");

const lib = JSON.parse(readFileSync(libraryPath, "utf8"));
const entries = Object.entries(lib.objects).map(([name, def]) => [
  name,
  {
    category: def.category,
    // Footprint in map tiles (16px), rounded to 1dp — enough for placement math.
    w: Math.round(def.tiles.w * 10) / 10,
    h: Math.round(def.tiles.h * 10) / 10,
    collides: Boolean(def.collides),
    tags: def.tags ?? [],
  },
]);
entries.sort(([a], [b]) => a.localeCompare(b));

const lines = entries.map(
  ([name, t]) =>
    `  ${JSON.stringify(name)}: { category: ${JSON.stringify(t.category)}, w: ${t.w}, h: ${t.h}, collides: ${t.collides}, tags: ${JSON.stringify(t.tags)} },`,
);

const out = `// GENERATED by scripts/gen-object-templates.mjs from
// apps/web/public/assets/objects/library.json — do not edit by hand; rerun the
// script when the object library changes. The template NAME is the shared
// vocabulary between agents (place_object), the contract (WorldObject.template),
// and the frontend renderer (TownObjects.placeTownObject).

export interface ObjectTemplate {
  category: string;
  // Footprint in 16px map tiles.
  w: number;
  h: number;
  collides: boolean;
  tags: string[];
}

export const OBJECT_TEMPLATES: Record<string, ObjectTemplate> = {
${lines.join("\n")}
};
`;

writeFileSync(outPath, out);
console.log(`wrote ${entries.length} templates to ${outPath}`);
